337: // --- Direct dispatch via Unix domain socket ---
338: 
339: #[cfg(unix)]
340: const DEFAULT_SOCKET_PATH: &str = "/tmp/adf-ctl.sock";
341: 
342: #[cfg(unix)]
343: fn resolve_socket_path() -> Result<PathBuf> {
344:     if let Ok(p) = std::env::var("ADF_DIRECT_SOCKET") {
345:         if !p.is_empty() {
346:             return Ok(PathBuf::from(p));
347:         }
348:     }
349:     if let Some(config_path) = discover_local_config() {
350:         if let Some(path) = parse_socket_path_from_toml(&config_path) {
351:             return Ok(path);
352:         }
353:     }
354:     if let Ok(orch_path) = std::env::var("ADF_ORCHESTRATOR_TOML") {
355:         if !orch_path.is_empty() {
356:             if let Some(path) = parse_socket_path_from_toml(Path::new(&orch_path)) {
357:                 return Ok(path);
358:             }
359:         }
360:     }
361:     let orch_toml = Path::new("/opt/ai-dark-factory/orchestrator.toml");
362:     if let Some(path) = parse_socket_path_from_toml(orch_toml) {
363:         return Ok(path);
364:     }
365:     Ok(PathBuf::from(DEFAULT_SOCKET_PATH))
366: }
367: 
368: #[cfg(unix)]
369: fn parse_socket_path_from_toml(path: &Path) -> Option<PathBuf> {
370:     let content = std::fs::read_to_string(path).ok()?;
371:     let parsed: toml::Value = toml::from_str(&content).ok()?;
372:     let socket = parsed.get("direct_dispatch")?.get("socket_path")?;
373:     socket.as_str().map(PathBuf::from)
374: }
375: 
376: #[cfg(unix)]
377: fn direct_dispatch_via_socket(
378:     socket_path: &Path,
379:     agent_name: &str,
380:     context: Option<&str>,
381: ) -> Result<()> {
382:     let payload = serde_json::json!({
383:         "agent": agent_name,
384:         "context": context.filter(|c| !c.is_empty()),
385:     });
386: 
387:     let mut stream = std::os::unix::net::UnixStream::connect(socket_path)
388:         .with_context(|| format!("failed to connect to {}", socket_path.display()))?;
389: 
390:     // Send newline-terminated JSON.
391:     writeln!(stream, "{payload}").context("failed to write to direct dispatch socket")?;
392: 
393:     // Read response.
394:     let mut response = String::new();
395:     stream
396:         .read_to_string(&mut response)
397:         .context("failed to read from direct dispatch socket")?;
398: 
399:     let response: serde_json::Value = serde_json::from_str(response.trim())
400:         .with_context(|| format!("invalid JSON from orchestrator: {}", response))?;
401: 
402:     match response.get("status").and_then(|s| s.as_str()) {
403:         Some("ok") => {
404:             println!("Agent dispatched via direct socket: {}", agent_name);
405:             println!("Monitor: journalctl -u adf-orchestrator -f");
406:             Ok(())
407:         }
408:         Some("error") => {
409:             let msg = response
410:                 .get("message")
411:                 .and_then(|m| m.as_str())
412:                 .unwrap_or("unknown error");
413:             bail!("Direct dispatch error: {}", msg);
414:         }
415:         _ => {
416:             bail!("Unexpected direct dispatch response: {}", response);
417:         }
418:     }
419: }
