423: #[allow(clippy::too_many_arguments)]
424: fn cmd_trigger(
425:     local: bool,
426:     name: &str,
427:     context: &str,
428:     host: &str,
429:     endpoint: &str,
430:     secret: Option<&str>,
431:     wait: bool,
432:     timeout: u64,
433:     direct: bool,
434: ) -> Result<()> {
435:     if direct && !local {
436:         anyhow::bail!("--direct requires --local");
437:     }
438: 
439:     #[cfg(not(unix))]
440:     if direct {
441:         anyhow::bail!("--direct dispatch requires Unix (UDS not available on this platform)");
442:     }
443: 
444:     if local {
445:         println!("[local mode]");
446:     }
447: 
448:     #[cfg(unix)]
449:     if direct {
450:         let socket_path = resolve_socket_path()?;
451:         direct_dispatch_via_socket(&socket_path, name, Some(context))?;
452:         if wait {
453:             println!(
454:                 "Waiting for agent '{}' to complete (timeout: {}s)...",
455:                 name, timeout
456:             );
457:             wait_for_agent_exit(local, name, host, timeout)?;
458:         }
459:         return Ok(());
460:     }
461: 
462:     let secret = resolve_secret(local, secret, host)?;
463:     let payload = build_payload(name, context);
464:     let sig = sign_payload(&secret, payload.as_bytes());
465: 
466:     if local {
467:         // Direct curl call (no SSH)
468:         let mut child = Command::new("curl")
469:             .arg("-s")
470:             .arg("-o")
471:             .arg("/dev/null")
472:             .arg("-w")
473:             .arg("%{http_code}")
474:             .arg("-X")
475:             .arg("POST")
476:             .arg(endpoint)
477:             .arg("-H")
478:             .arg("X-Gitea-Event: issue_comment")
479:             .arg("-H")
480:             .arg(format!("X-Gitea-Signature: sha256={}", sig))
481:             .arg("-H")
482:             .arg("Content-Type: application/json")
483:             .arg("--data-binary")
484:             .arg("@-")
485:             .stdin(Stdio::piped())
486:             .stdout(Stdio::piped())
487:             .stderr(Stdio::piped())
488:             .spawn()
489:             .context("failed to spawn curl")?;
490: 
491:         child
492:             .stdin
493:             .take()
494:             .expect("stdin is piped")
495:             .write_all(payload.as_bytes())
496:             .context("failed to write payload to curl stdin")?;
497: 
498:         let output = child.wait_with_output().context("curl wait failed")?;
499:         let http_code = String::from_utf8_lossy(&output.stdout).trim().to_string();
500:         let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
501: 
502:         if !stderr.is_empty() {
503:             eprintln!("curl stderr: {}", stderr);
504:         }
505: 
506:         match http_code.as_str() {
507:             "200" | "202" | "204" => {
508:                 println!("Agent dispatched: @adf:{} (HTTP {})", name, http_code);
509:                 println!("Monitor: journalctl -u adf-orchestrator -f");
510:             }
511:             "401" => bail!("Webhook authentication failed (check secret)"),
512:             "400" => bail!("Bad request (HTTP 400) - check payload format"),
513:             "503" => bail!("Orchestrator unavailable (HTTP 503)"),
514:             "" => bail!("No HTTP response - is the orchestrator running locally?"),
515:             code => bail!("Unexpected HTTP status: {}", code),
516:         }
517:     } else {
518:         // SSH-based dispatch
519:         let curl_cmd = format!(
520:             "curl -s -o /dev/null -w '%{{http_code}}' \
521:              -X POST {} \
522:              -H 'X-Gitea-Event: issue_comment' \
523:              -H 'X-Gitea-Signature: sha256={}' \
524:              -H 'Content-Type: application/json' \
525:              --data-binary @-",
526:             endpoint, sig
527:         );
528: 
529:         // Pipe JSON payload via stdin to avoid shell quoting issues with the JSON body
530:         let mut child = Command::new("ssh")
531:             .arg("-o")
532:             .arg("BatchMode=yes")
533:             .arg(host)
534:             .arg(&curl_cmd)
535:             .stdin(Stdio::piped())
536:             .stdout(Stdio::piped())
537:             .stderr(Stdio::piped())
538:             .spawn()
539:             .with_context(|| format!("failed to spawn ssh {}", host))?;
540: 
541:         child
542:             .stdin
543:             .take()
544:             .expect("stdin is piped")
545:             .write_all(payload.as_bytes())
546:             .context("failed to write payload to ssh stdin")?;
547: 
548:         let output = child.wait_with_output().context("ssh wait failed")?;
549:         let http_code = String::from_utf8_lossy(&output.stdout).trim().to_string();
550:         let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
551: 
552:         if !stderr.is_empty() {
553:             eprintln!("ssh stderr: {}", stderr);
554:         }
555: 
556:         match http_code.as_str() {
557:             "200" | "202" | "204" => {
558:                 println!("Agent dispatched: @adf:{} (HTTP {})", name, http_code);
559:                 println!("Monitor: ssh {} journalctl -u adf-orchestrator -f", host);
560:             }
561:             "401" => bail!("Webhook authentication failed (check secret)"),
562:             "400" => bail!("Bad request (HTTP 400) - check payload format"),
563:             "503" => bail!("Orchestrator unavailable (HTTP 503)"),
564:             "" => bail!(
565:                 "No HTTP response - is the orchestrator running on {}?",
566:                 host
567:             ),
568:             code => bail!("Unexpected HTTP status: {}", code),
569:         }
570:     }
571: 
572:     if wait {
573:         println!(
574:             "Waiting for agent '{}' to complete (timeout: {}s)...",
575:             name, timeout
576:         );
577:         wait_for_agent_exit(local, name, host, timeout)?;
578:     }
579: 
580:     Ok(())
581: }
