583: fn wait_for_agent_exit(local: bool, name: &str, host: &str, timeout_secs: u64) -> Result<()> {
584:     let start = std::time::Instant::now();
585:     let poll_interval = std::time::Duration::from_secs(10);
586: 
587:     loop {
588:         if start.elapsed().as_secs() >= timeout_secs {
589:             bail!(
590:                 "Timed out waiting for agent '{}' to complete after {}s",
591:                 name,
592:                 timeout_secs
593:             );
594:         }
595: 
596:         let elapsed_secs = start.elapsed().as_secs() + 1;
597:         let since = format!("{} seconds ago", elapsed_secs);
598:         let cmd = format!(
599:             "journalctl -u adf-orchestrator --since '{}' --no-pager 2>/dev/null \
600:              | grep 'exit classified agent={}'",
601:             since, name
602:         );
603: 
604:         let (stdout, _, _) = if local {
605:             local_run(&cmd)?
606:         } else {
607:             ssh_run(host, &cmd)?
608:         };
609: 
610:         if !stdout.trim().is_empty() {
611:             for line in stdout.lines() {
612:                 println!("{}", line);
613:             }
614:             if stdout.contains("exit_class=success") || stdout.contains("exit_class=empty_success")
615:             {
616:                 println!("Agent '{}' completed successfully.", name);
617:                 return Ok(());
618:             } else {
619:                 bail!(
620:                     "Agent '{}' exited with non-success status:\n{}",
621:                     name,
622:                     stdout.trim()
623:                 );
624:             }
625:         }
626: 
627:         std::thread::sleep(poll_interval);
628:     }
629: }
