631: fn cmd_status(local: bool, host: &str, since: &str, format: OutputFormat) -> Result<()> {
632:     if local {
633:         println!("[local mode]");
634:     }
635:     let journal_cmd = format!(
636:         "journalctl -u adf-orchestrator --since '{} ago' --no-pager 2>/dev/null \
637:          | grep -E 'exit classified|spawning agent|Agent spawned' | tail -30",
638:         since
639:     );
640:     let (journal_stdout, journal_stderr, _) = if local {
641:         local_run(&journal_cmd)?
642:     } else {
643:         ssh_run(host, &journal_cmd)?
644:     };
645:     let journal_output = JournalOutput {
646:         stdout: journal_stdout,
647:         stderr: journal_stderr,
648:     };
649: 
650:     let pgrep_cmd = if local {
651:         "ps -o pid,etimes,cputime,comm -p $(pgrep -d, -x 'claude|opencode|pi' 2>/dev/null) 2>/dev/null \
652:          || echo '(no agent CLI processes running)'"
653:             .to_string()
654:     } else {
655:         "ps -o pid,etimes,cputime,comm -p $(pgrep -d, claude 2>/dev/null) 2>/dev/null \
656:          || echo '(no agent CLI processes running)'"
657:             .to_string()
658:     };
659:     let (pgrep_stdout, _, _) = if local {
660:         local_run(&pgrep_cmd)?
661:     } else {
662:         ssh_run(host, &pgrep_cmd)?
663:     };
664: 
665:     let activity = parse_journal_activity(&journal_output.stdout);
666:     let processes = parse_running_processes(&pgrep_stdout);
667: 
668:     match format {
669:         OutputFormat::Human => {
670:             if !local {
671:                 println!(
672:                     "[best-effort via SSH process scan; not authoritative without admin socket]"
673:                 );
674:             } else {
675:                 println!("[best-effort via local process scan]");
676:             }
677:             println!();
678:             println!("=== Recent agent activity (last {}) ===", since);
679:             if !journal_output.stderr.is_empty() {
680:                 eprintln!("stderr: {}", journal_output.stderr);
681:             }
682:             if journal_output.stdout.trim().is_empty() {
683:                 println!("(no recent activity found)");
684:             } else {
685:                 print!("{}", journal_output.stdout);
686:             }
687:             println!();
688:             if local {
689:                 println!("=== Running agent CLI processes ===");
690:             } else {
691:                 println!("=== Running claude processes ===");
692:             }
693:             print!("{}", pgrep_stdout);
694:         }
695:         OutputFormat::Json => {
696:             let report = StatusReport {
697:                 host,
698:                 since,
699:                 recent_activity: activity,
700:                 running_processes: processes,
701:                 best_effort: true,
702:                 note: if local {
703:                     "best-effort via local process scan"
704:                 } else {
705:                     "best-effort via SSH process scan; not authoritative without admin socket"
706:                 },
707:             };
708:             println!("{}", serde_json::to_string_pretty(&report)?);
709:         }
710:     }
711: 
712:     Ok(())
713: }
