715: #[derive(Debug, Serialize)]
716: struct StatusReport<'a> {
717:     host: &'a str,
718:     since: &'a str,
719:     recent_activity: Vec<JournalEvent>,
720:     running_processes: Vec<ProcessInfo>,
721:     best_effort: bool,
722:     note: &'a str,
723: }
724: 
725: #[derive(Debug, Serialize, PartialEq, Eq)]
726: struct JournalEvent {
727:     line: String,
728: }
729: 
730: /// Raw output from a journalctl invocation, used in `cmd_status`.
731: #[derive(Debug)]
732: struct JournalOutput {
733:     stdout: String,
734:     stderr: String,
735: }
736: 
737: #[derive(Debug, Serialize, PartialEq, Eq)]
738: struct ProcessInfo {
739:     pid: String,
740:     etimes: String,
741:     cputime: String,
742:     comm: String,
743: }
744: 
745: /// Parse `journalctl` output filtered for orchestrator events into structured
746: /// records. Empty input or a single placeholder line yields an empty Vec so
747: /// JSON consumers see a stable `[]` rather than a noisy string.
748: fn parse_journal_activity(stdout: &str) -> Vec<JournalEvent> {
749:     stdout
750:         .lines()
751:         .map(str::trim)
752:         .filter(|l| !l.is_empty())
753:         .map(|l| JournalEvent {
754:             line: l.to_string(),
755:         })
756:         .collect()
757: }
758: 
759: /// Parse `ps -o pid,etimes,cputime,comm` output. The header row is dropped, as
760: /// is the `(no agent CLI processes running)` fallback emitted by the shell when
761: /// `pgrep` matches nothing.
762: fn parse_running_processes(stdout: &str) -> Vec<ProcessInfo> {
763:     stdout
764:         .lines()
765:         .map(str::trim)
766:         .filter(|l| !l.is_empty() && !l.starts_with("PID") && !l.starts_with("(no agent CLI"))
767:         .filter_map(|l| {
768:             let mut parts = l.split_whitespace();
769:             let pid = parts.next()?.to_string();
770:             let etimes = parts.next()?.to_string();
771:             let cputime = parts.next()?.to_string();
772:             let comm = parts.next()?.to_string();
773:             Some(ProcessInfo {
774:                 pid,
775:                 etimes,
776:                 cputime,
777:                 comm,
778:             })
779:         })
780:         .collect()
781: }
