783: fn cmd_cancel(local: bool, name: &str, host: &str) -> Result<()> {
784:     if local {
785:         println!("[local mode]");
786:     }
787:     if !local {
788:         println!("[best-effort via SSH process scan; not authoritative without admin socket]");
789:     }
790:     println!("Searching for agent '{}' processes on {}...", name, host);
791: 
792:     let find_cmd = if local {
793:         format!("ls .worktrees/ 2>/dev/null | grep '^{}-'", name)
794:     } else {
795:         format!("ls /tmp/adf-worktrees/ 2>/dev/null | grep '^{}-'", name)
796:     };
797:     let (worktrees, _, _) = if local {
798:         local_run(&find_cmd)?
799:     } else {
800:         ssh_run(host, &find_cmd)?
801:     };
802: 
803:     let pgrep_cmd = if local {
804:         "pgrep -a -x 'claude|opencode|pi' 2>/dev/null | grep -v defunct".to_string()
805:     } else {
806:         "pgrep -a claude 2>/dev/null | grep -v defunct".to_string()
807:     };
808:     let (procs, _, _) = if local {
809:         local_run(&pgrep_cmd)?
810:     } else {
811:         ssh_run(host, &pgrep_cmd)?
812:     };
813: 
814:     if worktrees.trim().is_empty() && procs.trim().is_empty() {
815:         println!(
816:             "No active worktrees or agent CLI processes found for '{}'.",
817:             name
818:         );
819:         return Ok(());
820:     }
821: 
822:     if !worktrees.trim().is_empty() {
823:         println!("Active worktrees for '{}':", name);
824:         for wt in worktrees.lines() {
825:             if local {
826:                 println!("  .worktrees/{}", wt.trim());
827:             } else {
828:                 println!("  /tmp/adf-worktrees/{}", wt.trim());
829:             }
830:         }
831:         println!();
832:     }
833: 
834:     if !procs.trim().is_empty() {
835:         println!("Running agent CLI processes:");
836:         for line in procs.lines() {
837:             println!("  {}", line);
838:         }
839:         println!();
840:         if local {
841:             println!("To kill a specific PID: kill <PID>");
842:         } else {
843:             println!("To kill a specific PID: ssh {} kill <PID>", host);
844:         }
845:         println!("(Phase 2 admin socket will provide authoritative cancel)");
846:     }
847: 
848:     Ok(())
849: }
