903: /// Discover a flow definition file from .terraphim/flows/<name>.toml
904: /// starting from cwd and walking up the directory tree.
905: fn discover_flow_file(cwd: &Path, name: &str) -> Option<PathBuf> {
906:     let mut current = Some(cwd.to_path_buf());
907:     while let Some(dir) = current {
908:         let flow_path = dir
909:             .join(".terraphim")
910:             .join("flows")
911:             .join(format!("{}.toml", name));
912:         if flow_path.is_file() {
913:             return Some(flow_path);
914:         }
915:         current = dir.parent().map(|p| p.to_path_buf());
916:     }
917:     None
918: }
