920: /// Parse context string (e.g. "issue=1882") into key-value pairs.
921: /// Returns a HashMap of parsed values.
922: fn parse_context(context: &str) -> std::collections::HashMap<String, String> {
923:     let mut map = std::collections::HashMap::new();
924:     for part in context.split_whitespace() {
925:         if let Some((k, v)) = part.split_once('=') {
926:             map.insert(k.trim().to_string(), v.trim().to_string());
927:         }
928:     }
929:     map
930: }
