947:     })?;
948: 
949:     println!("Loading flow from: {}", flow_path.display());
950: 
951:     let flow_content = std::fs::read_to_string(&flow_path)
952:         .with_context(|| format!("failed to read {}", flow_path.display()))?;
953: 
954:     let flow: FlowDefinition = toml::from_str(&flow_content)
955:         .with_context(|| format!("failed to parse flow TOML from {}", flow_path.display()))?;
956: 
957:     println!("Flow '{}' loaded: {} step(s)", flow.name, flow.steps.len());
958: 
959:     // Parse context for issue
960:     let ctx_map = parse_context(context);
961:     let issue = ctx_map.get("issue").cloned();
962: 
963:     // Create initial state with issue injected
964:     let mut state = FlowRunState::new(&flow.name);
965:     if let Some(ref iss) = issue {
966:         println!("Issue context: {}", iss);
967:         state = state.with_issue(iss.clone());
968:     }
969: 
970:     // Set up flow state directory
971:     let flow_state_dir = cwd.join(".terraphim").join("flow-state");
972:     std::fs::create_dir_all(&flow_state_dir).with_context(|| {
973:         format!(
974:             "failed to create flow state dir {}",
975:             flow_state_dir.display()
976:         )
977:     })?;
978: 
979:     // Build project runtime from the flow's project
980:     let project_runtime = ProjectRuntime {
981:         working_dir: cwd.clone(),
982:         gitea_owner: Some("terraphim".to_string()),
983:         gitea_repo: Some("terraphim-ai".to_string()),
984:     };
985: 
986:     let executor = FlowExecutor::new(cwd.clone(), flow_state_dir).with_projects(
987:         std::collections::HashMap::from([(flow.project.clone(), project_runtime)]),
988:     );
989: 
990:     // Run the flow
991:     println!("Running flow '{}'...", flow.name);
992:     let rt = tokio::runtime::Runtime::new().context("failed to create Tokio runtime")?;
993: 
994:     let final_state = rt
995:         .block_on(async { executor.run(&flow, Some(state)).await })
996:         .map_err(|e| anyhow::anyhow!("flow '{}' failed: {}", flow.name, e))?;
997: 
998:     // Print summary
999:     println!();
1000:     println!("Flow '{}' finished: {:?}", flow.name, final_state.status);
1001:     if let Some(ref err) = final_state.error {
1002:         println!("Error: {}", err);
1003:     }
1004:     println!(
1005:         "Steps completed: {}/{}",
1006:         final_state.step_envelopes.len(),
1007:         flow.steps.len()
1008:     );
1009: 
1010:     Ok(())
1011: }
